// Espera: {t_ms, seq, s:[s1,s2]}
const p = msg.payload;
if (!p || typeof p !== 'object') return null;

const t_ms = Number.isFinite(p.t_ms) ? p.t_ms : (Number.isFinite(p.t) ? p.t : null);
const seq  = Number.isFinite(p.seq) ? p.seq : null;
const sArr = Array.isArray(p.s) ? p.s : null;
if (t_ms === null || !sArr || sArr.length < 2) return null;

const s1 = parseInt(sArr[0], 10);
const s2 = parseInt(sArr[1], 10);
if (!Number.isFinite(s1) || !Number.isFinite(s2)) return null;

msg.topic = "sample";
msg.payload = { t_ms, seq, s1, s2 };
return msg;

/*
Entradas:
- msg.topic="sample" con msg.payload={t_ms,seq,s1,s2}
- msg.topic="cap_black"  (captura NEGRO usando última muestra)
- msg.topic="cap_white"  (captura BLANCO usando última muestra)
- msg.topic="reset_calib"
Salidas:
1 RAW chart (series s1,s2)      -> ui_chart
2 NORM chart (s1_norm,s2_norm)  -> ui_chart
3 Gauge s1
4 Gauge s2
5 Texto conteo
6 Texto parámetros (min/max/thr + Δ)
7 Texto detección (LINEA/NO)
8 File out (CSV, append)
*/

function init() {
    return {
        min_line: { s1: null, s2: null },
        max_floor:{ s1: null, s2: null },
        thr:      { s1: null, s2: null },
        captures: { black: [], white: [] },
        count: 0,
        headerWritten: false,
        last: null
    };
}

function isNum(x){ return Number.isFinite(x); }

function clamp01(x){
    if (!isNum(x)) return null;
    if (x < 0) return 0;
    if (x > 1) return 1;
    return x;
}

function compute(channel, val, st){
    var min = st.min_line[channel];
    var max = st.max_floor[channel];
    var thr = null, norm = null, line = null;

    if (isNum(min) && isNum(max) && (max !== min)){
        thr  = (min + max) / 2.0;
        norm = clamp01((val - min) / (max - min));

        if (min < max) line = (val <= thr);
        else          line = (val >= thr);
    }
    return {min:min, max:max, thr:thr, norm:norm, line:line};
}

function delta(last2){
    if (!last2 || last2.length < 2) return null;
    var a = last2[last2.length-2];
    var b = last2[last2.length-1];
    return { s1: Math.abs(b.s1 - a.s1), s2: Math.abs(b.s2 - a.s2) };
}

function fmt(n, d){
    if (!isNum(n)) return "—";
    return n.toFixed(d);
}

var st = flow.get("u1a5_calib") || init();

if (msg.topic === "reset_calib") {
    var keep = { count: st.count, headerWritten: st.headerWritten, last: st.last };
    st = init();
    st.count = keep.count;
    st.headerWritten = keep.headerWritten;
    st.last = keep.last;
    flow.set("u1a5_calib", st);

    var txt = "Calibración reiniciada.\n" +
              "1) Coloca sensores en NEGRO y presiona 'Capturar NEGRO'.\n" +
              "2) Coloca sensores en BLANCO y presiona 'Capturar BLANCO'.";
    return [null,null,null,null,null, {payload: txt}, null, null];
}

if (msg.topic === "cap_black" || msg.topic === "cap_white") {
    if (!st.last) return null;

    var cur = st.last;
    var cap = { t_ms: cur.t_ms, s1: cur.s1, s2: cur.s2 };

    if (msg.topic === "cap_black") {
        st.min_line.s1 = cap.s1;
        st.min_line.s2 = cap.s2;
        st.captures.black.push(cap);
        if (st.captures.black.length > 2) st.captures.black.shift();
    } else {
        st.max_floor.s1 = cap.s1;
        st.max_floor.s2 = cap.s2;
        st.captures.white.push(cap);
        if (st.captures.white.length > 2) st.captures.white.shift();
    }

    var c1 = compute("s1", cap.s1, st);
    var c2 = compute("s2", cap.s2, st);
    st.thr.s1 = c1.thr;
    st.thr.s2 = c2.thr;

    var dB = delta(st.captures.black);
    var dW = delta(st.captures.white);

    var txt = ""
      + "Captura: " + (msg.topic === "cap_black" ? "NEGRO (min_line)" : "BLANCO (max_floor)") + "\n"
      + "s1 min_line=" + fmt(st.min_line.s1,0) + " | max_floor=" + fmt(st.max_floor.s1,0) + " | thr=" + fmt(st.thr.s1,0) + "\n"
      + "s2 min_line=" + fmt(st.min_line.s2,0) + " | max_floor=" + fmt(st.max_floor.s2,0) + " | thr=" + fmt(st.thr.s2,0) + "\n"
      + "Δ Repetibilidad (últimas 2 capturas):\n"
      + "  NEGRO:  Δs1=" + (dB? fmt(dB.s1,0):"—") + " , Δs2=" + (dB? fmt(dB.s2,0):"—") + "\n"
      + "  BLANCO: Δs1=" + (dW? fmt(dW.s1,0):"—") + " , Δs2=" + (dW? fmt(dW.s2,0):"—") + "\n";

    flow.set("u1a5_calib", st);
    return [null,null,null,null,null, {payload: txt}, null, null];
}

if (msg.topic !== "sample") return null;

var t_ms = msg.payload.t_ms;
var s1 = msg.payload.s1;
var s2 = msg.payload.s2;

st.count += 1;
st.last = msg.payload;

var c1s = compute("s1", s1, st);
var c2s = compute("s2", s2, st);
st.thr.s1 = c1s.thr;
st.thr.s2 = c2s.thr;

var rawMsgs = [
  { topic: "s1", payload: s1, timestamp: Date.now() },
  { topic: "s2", payload: s2, timestamp: Date.now() }
];

var normMsgs = [
  { topic: "s1_norm", payload: (c1s.norm===null? null : Number(c1s.norm.toFixed(4))), timestamp: Date.now() },
  { topic: "s2_norm", payload: (c2s.norm===null? null : Number(c2s.norm.toFixed(4))), timestamp: Date.now() }
];

var g1 = { payload: s1 };
var g2 = { payload: s2 };

var countMsg = { payload: "Muestras recibidas: " + st.count + " | t_ms (última): " + t_ms };

var dB = delta(st.captures.black);
var dW = delta(st.captures.white);

var paramsTxt = ""
  + "Parámetros actuales:\n"
  + "s1 min_line=" + fmt(st.min_line.s1,0) + " | max_floor=" + fmt(st.max_floor.s1,0) + " | thr=" + fmt(st.thr.s1,0) + "\n"
  + "s2 min_line=" + fmt(st.min_line.s2,0) + " | max_floor=" + fmt(st.max_floor.s2,0) + " | thr=" + fmt(st.thr.s2,0) + "\n"
  + "Δ Repetibilidad (últimas 2 capturas):\n"
  + "  NEGRO:  Δs1=" + (dB? fmt(dB.s1,0):"—") + " , Δs2=" + (dB? fmt(dB.s2,0):"—") + "\n"
  + "  BLANCO: Δs1=" + (dW? fmt(dW.s1,0):"—") + " , Δs2=" + (dW? fmt(dW.s2,0):"—") + "\n"
  + "Norm (0–1): s1=" + (c1s.norm===null? "—": fmt(c1s.norm,3)) + " | s2=" + (c2s.norm===null? "—": fmt(c2s.norm,3)) + "\n";

var paramsMsg = { payload: paramsTxt };

var line1 = (c1s.line===null? "—" : (c1s.line? "LINEA":"NO LINEA"));
var line2 = (c2s.line===null? "—" : (c2s.line? "LINEA":"NO LINEA"));
var lineMsg = { payload: "s1: " + line1 + " | s2: " + line2 };

var thr1 = (isNum(st.thr.s1) ? Number(st.thr.s1.toFixed(1)) : "");
var thr2 = (isNum(st.thr.s2) ? Number(st.thr.s2.toFixed(1)) : "");
var n1 = (c1s.norm===null? "" : Number(c1s.norm.toFixed(4)));
var n2 = (c2s.norm===null? "" : Number(c2s.norm.toFixed(4)));
var l1 = (c1s.line===null? "" : (c1s.line? 1:0));
var l2 = (c2s.line===null? "" : (c2s.line? 1:0));

var row = [t_ms, s1, s2, n1, n2, thr1, thr2, l1, l2].join(",");

var fileMsgs = [];
if (!st.headerWritten) {
    st.headerWritten = true;
    fileMsgs.push({ payload: "t_ms,s1,s2,s1_norm,s2_norm,thr1,thr2,line1,line2" });
}
fileMsgs.push({ payload: row });

flow.set("u1a5_calib", st);

return [rawMsgs, normMsgs, g1, g2, countMsg, paramsMsg, lineMsg, fileMsgs];
